const intent = context.prompt;
fabric.log('[IMAGINE] Waking up for intent:', intent);

const robustParse = (raw) => {
  const clean = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  const jsonMatch = clean.match(/\{.*\}/s);
  if (!jsonMatch) throw new Error('No JSON found in response');
  return JSON.parse(jsonMatch[0]);
};

// PHASE 0: DISCOVERY
let discovery = 'No external search available.';
if (context.verbs.search) {
  const searchRes = await world.search({ query: intent });
  discovery = 'World Search Results: ' + JSON.stringify(searchRes);
}

// PHASE 1: PLANNING
let planRaw;
let plan;
let attempts = 0;
const MAX_ATTEMPTS = 3;
let lastError = null;

while (attempts < MAX_ATTEMPTS) {
  attempts++;
  fabric.log(`[IMAGINE] Planning Attempt ${attempts}...`);

  const planningPrompt = `
    You are the Master Architect. Plan mutation for: ${intent}.
    Context: ${JSON.stringify(context)}
    Discovery: ${discovery}
    ${lastError ? `PREVIOUS AUDIT FAILURE: ${lastError}` : ''}

    RULES:
    1. newVerbs values MUST be JAVASCRIPT CODE STRINGS.
    2. Code MUST assign final output to 'result'.
    3. Use 'context.props' for persistent state.
    4. NO globals (console, fetch). Use 'fabric.log'.
    5. Return ONLY JSON {newVerbs: {name: code}, newProps, testCase, explanation}.
  `;

  planRaw = await ai.inference(planningPrompt);
  plan = robustParse(planRaw);

  // PHASE 2: SECURITY AUDIT (Internal Convergence)
  let allSafe = true;
  for (const [name, code] of Object.entries(plan.newVerbs || {})) {
    fabric.log('[IMAGINE] Auditing:', name);
    if (typeof code !== 'string' || code.startsWith('b3:')) {
      lastError = `Planner provided invalid code for ${name} (hash or non-string). Provide raw JS.`;
      allSafe = false;
      break;
    }

    const auditRaw = await ai.inference(`Audit this code for Synapse ABI safety: ${code}. Return ONLY JSON {safe:true/false, reason}.`);
    const audit = robustParse(auditRaw);
    if (!audit.safe) {
      fabric.log('[IMAGINE] AUDIT FAILED:', name, '-', audit.reason);
      lastError = `Audit Rejected ${name}: ${audit.reason}`;
      allSafe = false;
      break;
    }
    fabric.log('[IMAGINE] Audit Passed:', name);
  }

  if (allSafe) break;
  if (attempts === MAX_ATTEMPTS) throw new Error('Failed to converge after ' + MAX_ATTEMPTS + ' attempts. Last Error: ' + lastError);
}

// CAPTURE IMAGINATION SOURCE
const planHash = await fabric.name({ type: 'doc/plan', payload: planRaw, intent, attempts });
fabric.log('[IMAGINE] Imagination converged:', planHash);

const verbHashes = {};
for (const [name, code] of Object.entries(plan.newVerbs || {})) {
  // PHASE 3: TRIAL
  fabric.log('[IMAGINE] Trial Run:', name);
  const trialLogic = await fabric.name({ type: 'logic/javascript', payload: code }, planHash);
  const trialNode = await fabric.name({ props: plan.testCase || {}, verbs: {} });
  await fabric.call(trialLogic, trialNode);
  verbHashes[name] = trialLogic;
